CREATE TABLE IF NOT EXISTS interaction_events (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE, subject_account_id BIGINT NOT NULL REFERENCES instagram_accounts(id) ON DELETE CASCADE, related_account_username TEXT, media_item_id BIGINT REFERENCES media_items(id) ON DELETE SET NULL, event_type TEXT NOT NULL CHECK (event_type IN ('comment_inbound','mention_inbound','message_inbound','comment_outbound','like_outbound','follow_edge_added','follow_edge_removed','ad_seen','snapshot_refresh')), event_time TIMESTAMPTZ NOT NULL, confidence_score NUMERIC(5,4) NOT NULL DEFAULT 1.0, source_name TEXT NOT NULL, payload JSONB);
